// Normalize field names: accept React camelCase OR Google Forms column names.
// Webhook nests POST body under $json.body -- unwrap it.
const raw = $input.first().json;
const item = raw.body || raw;
const get = (name) => {
  const v = item[name];
  if (v !== undefined && v !== null) return v;
  const key = Object.keys(item).find(k => k.trim() === name);
  return key !== undefined ? item[key] : undefined;
};

const bookingUid        = (item.bookingId        || get('Booking ID')                       || '').toString().trim();
const cleanerIdFromForm = (item.cleanerId         || get('Cleaner ID')                       || '').toString().trim();
const confirmCheckout   = (item.confirmCheckout   || get('Confirm Checkout')                 || '').toString().trim();
const captureLocation   = (item.captureLocation   || get('Capture Location (GPS)')           || get('Capture Location') || '').toString().trim();
const submittedAt       = (item.submittedAt       || get('Timestamp')                        || new Date().toISOString()).toString();

const issueReported = (item.issueReported     || get('Any maintenance issues to report?') || '').toString().trim();
const issueType     = (item.issueType         || get('Issue Type')                        || '').toString().trim();
const description   = (item.issueDescription  || get('Issue Description')                || '').toString().trim();
const photoUrl      = (Array.isArray(item.photoUrls) ? item.photoUrls.join(',') : (item.photoUrls || get('Photo of Issue') || '')).toString().trim();
const priority      = (item.issuePriority     || get('Issue Priority')                    || '').toString().trim();
const lowStockAlert = (item.lowStockAlert     || get('Low Stock Alert')                   || '').toString().trim();

const supplyColMap = {
  'Trash Bags \u2014 Qty Used':          'Trash Bags',
  'All-Purpose Cleaner \u2014 Qty Used': 'All-Purpose Cleaner',
  'Glass Cleaner \u2014 Qty Used':       'Glass Cleaner',
  'Disinfectant \u2014 Qty Used':        'Disinfectant',
  'Toilet Cleaner \u2014 Qty Used':      'Toilet Cleaner',
  'Floor Cleaner \u2014 Qty Used':       'Floor Cleaner',
  'Sponges \u2014 Qty Used':             'Sponges',
  'Paper Towels \u2014 Qty Used':        'Paper Towels',
  'Laundry Detergent \u2014 Qty Used':   'Laundry Detergent',
  'Fabric Softener \u2014 Qty Used':     'Fabric Softener',
  'Dish Soap \u2014 Qty Used':           'Dish Soap',
  'Air Freshener \u2014 Qty Used':       'Air Freshener',
  'Microfiber Cloths \u2014 Qty Used':   'Microfiber Cloths',
  'Mop Pads \u2014 Qty Used':            'Mop Pads'
};

let supplies = [];
if (Array.isArray(item.supplies)) {
  // React app format: [{itemName, quantityUsed}]
  supplies = item.supplies.filter(s => s && s.itemName && parseInt(s.quantityUsed, 10) > 0)
             .map(s => ({ itemName: s.itemName, quantityUsed: parseInt(s.quantityUsed, 10) }));
} else if (item.supplies && typeof item.supplies === 'object') {
  // Flat object format: {name: qty}
  for (const [itemName, qty] of Object.entries(item.supplies)) {
    const q = parseInt(qty, 10);
    if (!isNaN(q) && q > 0) supplies.push({ itemName, quantityUsed: q });
  }
} else {
  // Google Forms column format
  for (const [col, itemName] of Object.entries(supplyColMap)) {
    const raw = (get(col) || '').toString().trim();
    const qty = raw === '' ? 0 : parseInt(raw, 10);
    if (!isNaN(qty) && qty > 0) supplies.push({ itemName, quantityUsed: qty });
  }
}

const isShortLink = /^(https?:\/\/)?(www\.)?(maps\.app\.goo\.gl|goo\.gl\/maps)\/\S+/i.test(captureLocation);

return [{ json: {
  bookingUid, cleanerIdFromForm, confirmCheckout, captureLocation, isShortLink,
  submittedAt, issueReported, issueType, description, photoUrl, priority, lowStockAlert, supplies
} }];

try {
  const form = $('Normalize and Check').first().json;
  if (!form.bookingUid) throw new Error('Booking ID is missing');
  if (!form.cleanerIdFromForm) throw new Error('Cleaner ID is missing');
  if (!form.confirmCheckout || form.confirmCheckout.toLowerCase() !== 'yes') throw new Error('Checkout not confirmed');
  if (!form.captureLocation) throw new Error('Location link missing');

  function parseLatLngFromString(str) {
    const m = str.match(/(-?\d+\.\d+),(-?\d+\.\d+)/);
    if (m) return { lat: m[1], lng: m[2] };
    const dmsRegex = /(\d+)[\u00b0\u00ba]\s*(\d+)['\u2032']\s*([\d.]+)["\u2033]?\s*([NS])\s*(\d+)[\u00b0\u00ba]\s*(\d+)['\u2032']\s*([\d.]+)["\u2033]?\s*([EW])/i;
    const dms = str.match(dmsRegex);
    if (!dms) return null;
    const latSign = dms[4].toUpperCase() === 'S' ? -1 : 1;
    const lngSign = dms[8].toUpperCase() === 'W' ? -1 : 1;
    const lat = latSign * (parseInt(dms[1],10) + parseInt(dms[2],10)/60 + parseFloat(dms[3])/3600);
    const lng = lngSign * (parseInt(dms[5],10) + parseInt(dms[6],10)/60 + parseFloat(dms[7])/3600);
    return { lat: String(lat), lng: String(lng) };
  }
  const parsed = parseLatLngFromString(form.captureLocation);
  const gpsLat = parsed ? parsed.lat : '';
  const gpsLng = parsed ? parsed.lng : '';

  return [{ json: {
    ...form,
    gpsLat, gpsLng,
    submissionTimestamp: form.submittedAt,
    processingStatus: 'PENDING', resultMessage: '', processedAt: '',
    hasError: false
  } }];
} catch (err) {
  const form = $('Normalize and Check').first().json;
  return [{ json: { hasError: true, errorMessage: err.message, bookingUid: form.bookingUid || 'unknown', cleanerIdFromForm: form.cleanerIdFromForm || '', submissionTimestamp: form.submittedAt || new Date().toISOString() } }];
}

const existing = $input.all();
const parsed = $('ParseAndValidate').first().json;
if (!parsed || parsed.hasError) throw new Error('Missing parsed submission');
const hasApproved = existing.some(i => (i.json?.processingStatus ?? '').toString().trim() === 'APPROVED');
if (hasApproved) return [{ json: { skipInsert: true, bookingUid: parsed.bookingUid } }];
return [{ json: { ...parsed, skipInsert: false } }];

