// Merge inserted-row submission with its CleaningJobs row.
// Explicitly keep submission's row_number so downstream Sheets updates
// target the correct CheckoutSubmissions row, not the CleaningJobs row.
const submissionItems = $('Lookup Inserted Row').all();
const jobItems = $input.all();
return jobItems.map((jobItem, i) => {
  const submission = submissionItems[i]?.json || {};
  const job = jobItem.json || {};
  return { json: { ...submission, ...job, row_number: submission.row_number } };
});

// Run all pre-GPS validations: cleaner match, clock-in status, duration min/max.
const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const cleanerFromForm = (j.cleanerIdFromForm ?? '').toString().trim();
  const assignedCleaner = (j.cleanerId ?? '').toString().trim();
  if (!cleanerFromForm || !assignedCleaner || cleanerFromForm !== assignedCleaner) {
    return { json: { ...j, validationPass: 'FAIL', validationReason: 'cleaner_mismatch', validationMsg: 'You are not assigned to this booking. Please contact admin.' } };
  }
  const jobStatus = (j.status ?? '').toString().trim();
  if (jobStatus !== 'IN_PROGRESS') {
    return { json: { ...j, validationPass: 'FAIL', validationReason: 'not_clocked_in', validationMsg: 'No approved clock-in found for this booking. Please clock in first.' } };
  }
  const clockInTime = j.clockInTimeUTC ? new Date(j.clockInTimeUTC) : null;
  const checkoutTime = j.submissionTimestamp ? new Date(j.submissionTimestamp) : null;
  if (!clockInTime || isNaN(clockInTime.getTime()) || !checkoutTime || isNaN(checkoutTime.getTime())) {
    return { json: { ...j, validationPass: 'FAIL', validationReason: 'invalid_timestamp', validationMsg: 'Invalid timestamp \u2014 cannot calculate duration.' } };
  }
  const durationMin = Math.round((checkoutTime.getTime() - clockInTime.getTime()) / 60000);
  if (durationMin < 30) {
    return { json: { ...j, validationPass: 'FAIL', validationReason: 'too_soon', validationMsg: 'Checkout too soon (' + durationMin + ' min after clock-in). Minimum is 30 minutes.', durationMinutes: durationMin } };
  }
  if (durationMin > 360) {
    const durationHrs = (durationMin / 60).toFixed(1);
    return { json: { ...j, validationPass: 'FAIL', validationReason: 'too_late', validationMsg: 'Checkout too late (' + durationHrs + ' hrs after clock-in). Maximum is 6 hours.', durationMinutes: durationMin } };
  }
  return { json: { ...j, validationPass: 'PASS', validationReason: 'ok', validationMsg: 'Pre-GPS checks passed', durationMinutes: durationMin } };
});

