// Combine by position: validated submission (Pass Validated Items) with coords (Get Property Coordinates).
// Explicitly keep submission's row_number so downstream CheckoutSubmissions updates target the right row.
const submissionItems = $('Pass Validated Items').all();
const coordsItems = $input.all();
const len = Math.min(submissionItems.length, coordsItems.length);
if (len === 0) return [];
const out = [];
for (let i = 0; i < len; i++) {
  const sub = submissionItems[i]?.json || {};
  const coord = coordsItems[i]?.json || {};
  out.push({ json: { ...sub, ...coord, row_number: sub.row_number } });
}
return out;

// Haversine distance in meters between cleaner GPS and property GPS.
const items = $input.all();
const R = 6371000;
const toRad = deg => deg * (Math.PI / 180);
return items.map(item => {
  const j = item.json || {};
  const userLat = parseFloat(j.gpsLat);
  const userLng = parseFloat(j.gpsLng);
  const propertyLat = parseFloat(j.latitude);
  const propertyLng = parseFloat(j.longitude);
  let distance = NaN;
  if (Number.isFinite(userLat) && Number.isFinite(userLng) && Number.isFinite(propertyLat) && Number.isFinite(propertyLng)) {
    const dLat = toRad(propertyLat - userLat);
    const dLng = toRad(propertyLng - userLng);
    const a = Math.sin(dLat/2)*Math.sin(dLat/2) + Math.cos(toRad(userLat))*Math.cos(toRad(propertyLat))*Math.sin(dLng/2)*Math.sin(dLng/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    distance = R * c;
  }
  return { json: { ...j, distance: Number.isFinite(distance) ? Math.round(distance) : 999999 } };
});

